function solve(grid, x, y, k) {
    // Make a deep copy of the grid to avoid modifying the original directly
    const newGrid = grid.map(row => [...row]);
    // Calculate the end row and column of the submatrix
    const endX = x + k - 1;
    const endY = y + k - 1;

    // Iterate over the rows within the submatrix
    for (let i = 0; i < Math.floor(k / 2); i++) {
        const row1 = x + i;
        const row2 = endX - i;
        // Swap the rows row1 and row2 within the submatrix columns
        for (let j = y; j <= endY; j++) {
            const temp = newGrid[row1][j];
            newGrid[row1][j] = newGrid[row2][j];
            newGrid[row2][j] = temp;
        }
    }

    return newGrid;
}

